import type { ComponentPropsWithoutRef } from 'react';
import { Button as ButtonPrimitive } from '@base-ui/react/button';
import clsx from 'clsx';
import { CloseIcon } from '@/lib/moduix/icons/ui';
import styles from './Tag.module.css';

type TagVariant = 'default' | 'secondary' | 'outline' | 'ghost' | 'destructive';
type TagSize = 'sm' | 'md';
type TagProps = ComponentPropsWithoutRef<'span'> & {
  variant?: TagVariant;
  size?: TagSize;
};
type TagLabelProps = ComponentPropsWithoutRef<'span'>;
type TagRemoveProps = ButtonPrimitive.Props;

const DEFAULT_REMOVE_LABEL = 'Remove tag';

function Tag({ className, size = 'md', variant = 'default', ...props }: TagProps) {
  return (
    <span
      data-slot="tag-root"
      data-size={size}
      data-variant={variant}
      className={clsx(styles.root, className)}
      {...props}
    />
  );
}

function TagLabel({ className, ...props }: TagLabelProps) {
  return <span data-slot="tag-label" className={clsx(styles.label, className)} {...props} />;
}

function TagRemove({
  className,
  children,
  type = 'button',
  'aria-label': ariaLabel,
  'aria-labelledby': ariaLabelledBy,
  ...props
}: TagRemoveProps) {
  return (
    <ButtonPrimitive
      type={type}
      data-slot="tag-remove"
      className={clsx(styles.remove, className)}
      aria-label={
        ariaLabel ?? (children == null && ariaLabelledBy == null ? DEFAULT_REMOVE_LABEL : undefined)
      }
      aria-labelledby={ariaLabelledBy}
      {...props}
    >
      {children ?? <CloseIcon />}
    </ButtonPrimitive>
  );
}

export { Tag, TagLabel, TagRemove };
export type { TagProps, TagSize, TagVariant, TagLabelProps, TagRemoveProps };

@layer ui.components {
  .root {
    display: inline-flex;
    width: fit-content;
    max-width: 100%;
    min-width: 0;
    box-sizing: border-box;
    align-items: center;
    gap: var(--tag-gap, 0.375rem);
    border: var(--tag-border-width, var(--border-width-sm)) solid
      var(--tag-border-color, color-mix(in oklab, var(--color-foreground) 10%, transparent));
    border-radius: var(--tag-radius, var(--radius-full));
    background-color: var(--tag-bg, color-mix(in oklab, var(--color-primary) 8%, transparent));
    color: var(--tag-color, var(--color-foreground));
    font-size: var(--tag-font-size, var(--text-xs));
    font-weight: var(--tag-font-weight, var(--weight-medium));
    line-height: var(--tag-line-height, var(--line-height-text-xs));
    min-height: var(--tag-height-md, 1.5rem);
    padding-block: var(--tag-padding-y-md, 0.125rem);
    padding-inline: var(--tag-padding-x-md, 0.5rem);
    white-space: nowrap;
    vertical-align: middle;
    transition:
      color var(--tag-transition, var(--transition-default)),
      background-color var(--tag-transition, var(--transition-default)),
      border-color var(--tag-transition, var(--transition-default));

    > svg {
      width: var(--tag-icon-size, 0.75rem);
      height: var(--tag-icon-size, 0.75rem);
      flex-shrink: 0;
      pointer-events: none;
    }

    &[data-size='sm'] {
      gap: var(--tag-gap-sm, 0.25rem);
      min-height: var(--tag-height-sm, 1.25rem);
      padding-block: var(--tag-padding-y-sm, 0);
      padding-inline: var(--tag-padding-x-sm, 0.375rem);
    }

    &[data-variant='secondary'] {
      background-color: var(--tag-bg, color-mix(in oklab, var(--color-secondary) 20%, transparent));
      border-color: var(
        --tag-border-color,
        color-mix(in oklab, var(--color-secondary) 30%, transparent)
      );
      color: var(--tag-color, var(--color-secondary-foreground));
    }

    &[data-variant='outline'] {
      background-color: var(--tag-bg, transparent);
      border-color: var(--tag-border-color, var(--color-border));
      color: var(--tag-color, var(--color-foreground));
    }

    &[data-variant='ghost'] {
      background-color: var(--tag-bg, transparent);
      border-color: var(--tag-border-color, transparent);
      color: var(--tag-color, var(--color-foreground));
    }

    &[data-variant='destructive'] {
      background-color: var(
        --tag-bg,
        color-mix(in oklab, var(--color-destructive) 12%, transparent)
      );
      border-color: var(
        --tag-border-color,
        color-mix(in oklab, var(--color-destructive) 30%, transparent)
      );
      color: var(--tag-color, var(--color-destructive));
    }
  }

  .label {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .remove {
    display: inline-flex;
    width: var(--tag-remove-size, 1rem);
    height: var(--tag-remove-size, 1rem);
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    border: 0;
    border-radius: var(--tag-remove-radius, var(--radius-full));
    padding: 0;
    background-color: var(--tag-remove-bg, transparent);
    color: inherit;
    cursor: pointer;
    transition:
      color var(--tag-transition, var(--transition-default)),
      background-color var(--tag-transition, var(--transition-default)),
      box-shadow var(--tag-transition, var(--transition-default));

    > svg {
      width: var(--tag-remove-icon-size, 0.625rem);
      height: var(--tag-remove-icon-size, 0.625rem);
      flex-shrink: 0;
      pointer-events: none;
    }

    &:hover {
      background-color: var(
        --tag-remove-bg-hover,
        color-mix(in oklab, currentColor 12%, transparent)
      );
    }

    &:focus-visible {
      outline: none;
      box-shadow:
        0 0 0 var(--tag-remove-focus-ring-offset, 0)
          var(--tag-remove-focus-ring-offset-color, transparent),
        0 0 0
          calc(
            var(--tag-remove-focus-ring-width, var(--border-width-sm)) +
              var(--tag-remove-focus-ring-offset, 0)
          )
          var(--tag-remove-focus-ring-color, var(--color-ring));
    }

    &[disabled],
    &[data-disabled] {
      cursor: default;
      opacity: var(--tag-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }
  }
}
